settings.custom_liquid:
{% if request.page_type == 'index' %}
<div class="homepage-system-spec">
  <div class="spec-container">

    <div class="spec-label">
      <span class="status-indicator"></span> 
      HARDWARE FEATURE: THE LIVING DOCUMENT
    </div>

    <div class="spec-text-block">
      <p class="spec-body">Every garment is equipped with a high-density QR code on the left sleeve. In a world of partisan noise, we provide the source code.</p>
      <p class="spec-highlight">Scan to access the full text of the U.S. Constitution instantly.</p>
    </div>

  </div>
</div>

<style>
.homepage-system-spec {
  background: #0A0A08 !important; 
  padding: 80px 20px !important; 
  margin-top: 50px !important;    
  border-top: 1px solid rgba(196,162,78,0.15);
  border-bottom: 1px solid rgba(196,162,78,0.15);
  width: 100% !important;
  display: flex !important;
  justify-content: center !important;
}

.spec-container {
  max-width: 800px !important;
  width: 100%;
  display: flex !important;
  flex-direction: column !important;
  align-items: center !important; /* Forces children to center */
  text-align: center !important;
}

.spec-label {
  font-family: 'Barlow Condensed', sans-serif !important; 
  color: #A82020 !important; 
  letter-spacing: 3px !important;
  font-weight: 700 !important;
  margin-bottom: 25px !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  text-transform: uppercase !important;
}

.status-indicator {
  width: 10px;
  height: 10px;
  background: #A82020;
  border-radius: 50%;
  margin-right: 12px;
  box-shadow: 0 0 8px #A82020;
  animation: specPulse 2s infinite;
}

.spec-body {
  font-family: 'Cormorant Garamond', serif !important; 
  color: #F0EBE0 !important; 
  font-size: 1.35rem !important;
  line-height: 1.6 !important;
  margin: 0 auto 15px auto !important;
}

.spec-highlight {
  font-family: 'Barlow Condensed', sans-serif !important;
  color: #C4A24E !important; 
  text-transform: uppercase !important;
  font-weight: 600 !important;
  letter-spacing: 2px !important;
  font-size: 1.2rem !important;
  margin: 0 !important;
}

@keyframes specPulse {
  0% { opacity: 1; }
  50% { opacity: 0.4; }
  100% { opacity: 1; }
}
</style>
{% endif %}
